    'antwerp_port_assembly.body.1': 'The facility marks a key step in Windrose\'s European manufacturing strategy, enabling local assembly and distribution of electric trucks across the continent.',
    'antwerp_port_assembly.headline': 'Port of Antwerp-Bruges Welcomes Windrose for European Assembly',
    'antwerp_port_assembly.stat_label.0': 'Location',
