    'antwerp_port_assembly.stat_label.2': 'Address',
    'antwerp_port_assembly.subline': 'Windrose establishes Windrose Park Antwerp along Noorderlaan — its first European electric truck assembly facility.',
    'antwerp_port_assembly.type': 'Press Release',
    'assembly.desc': 'Seven straightforward steps — any certified local partner, no specialist tooling required. Reduces logistics cost, creates local jobs, enables rapid market entry across 5 continents.',
    'assembly.h2': 'Simplified & localised final assembly',
    'assembly.label': 'Local Assembly',
    'atc_2600km_netherlands_hungary.body.0': 'ATC Computer Transport & Logistics completed a landmark 2,600 km round trip from Venlo, Netherlands to Budapest, Hungary using a Windrose electric truck — proving that battery-electric trucks can match diesel on demanding cross-border European routes.',
    'atc_2600km_netherlands_hungary.body.1': 'The trial crossed',
    'atc_2600km_netherlands_hungary.headline': 'ATC Completes 2,600 km Electric Truck Trial — Venlo to Budapest and Back',
    'atc_2600km_netherlands_hungary.stat_label.0': 'Round trip',
